function esc(value) {
  return String(value || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

function titleFromSlug(slug) {
  return slug.split('-').map((part) => caps[part] || part.charAt(0).toUpperCase() + part.slice(1)).join(' ');
}

function list(items) {
  return `<ul class="wi-detail-list">${items.map((item) => `<li>${item}</li>`).join('')}</ul>`;
}

function relatedLinks(slugs) {
  return slugs.map((slug) => `<a href="/seo-pages/${slug}.html">${esc(titleFromSlug(slug))}</a>`).join('');
}

function factPanel(page) {
  const taxTransition = page.refType === 'tax'
    ? '<p><strong>Transition rule:</strong> AY 2026-27 covers FY 2025-26 and continues under the Income-tax Act, 1961. The Income-tax Act 2025 Tax Year terminology applies for income earned from 1 April 2026 onward.</p>'
    : '';
  const gstCaution = page.refType === 'gst'
    ? '<p><strong>GST caution:</strong> GST rates, due dates and portal behaviour should be checked against the live GST portal, CBIC notifications and current return utilities before filing.</p>'
    : '';
  return `<section class="wi-panel"><div class="lp-section-eyebrow">Official fact-check status</div><h2>Fact-check notes</h2><p><strong>Last fact-checked:</strong> ${factDate}</p>${taxTransition}${gstCaution}<p>This page is written from official portal guidance and the supplied Batch 11 brief. Any future-dated form, rule or portal workflow should be verified in the active utility before filing or advising a client.</p></section>`;
}

function section202Calculator() {
  return `<section class="wi-panel"><div class="lp-section-eyebrow">Calculator</div><h2>Section 202 slab calculator - Tax Year 2026-27</h2><p>This quick calculator uses the Section 202 slab structure stated for the new Act pages. It is for Tax Year 2026-27 planning. For AY 2026-27 returns for FY 2025-26, use the AY 2026-27 calculator page because that return remains under the 1961 Act.</p><div class="wi-calc-grid"><label>Taxpayer category<select id="wi202-taxpayer"><option value="resident-individual">Resident individual</option><option value="non-resident">Non-resident individual</option><option value="huf">HUF / AOP / BOI</option></select></label><label>Taxable normal income<input id="wi202-normal" type="number" min="0" value="1200000"></label><label>Special-rate income<input id="wi202-special" type="number" min="0" value="0"></label><label>TDS / advance tax credits<input id="wi202-credit" type="number" min="0" value="0"></label></div><button class="wi-calc-button" type="button" id="wi202-run">Calculate</button><div class="wi-calc-result" id="wi202-result">Enter values and calculate.</div><p class="wi-small-note">Rebate is modelled only for resident individuals on normal slab income up to Rs. 12,00,000; it is not applied against special-rate income. Cess is 4%.</p></section>`;
}

function calculatorScript(page) {
  if (page.slug !== 'income-tax-slabs-section-202-2026-27') return '';
  return `<script>
function wi202SlabTax(income){var bands=[[400000,0],[800000,.05],[1200000,.10],[1600000,.15],[2000000,.20],[2400000,.25],[Infinity,.30]],tax=0,low=0;for(var i=0;i<bands.length;i++){var up=bands[i][0],rate=bands[i][1];if(income>low)tax+=(Math.min(income,up)-low)*rate;low=up;if(income<=up)break;}return Math.max(0,tax);}
function wi202Format(n){return 'Rs. '+Math.round(n).toLocaleString('en-IN');}
document.addEventListener('DOMContentLoaded',function(){var run=document.getElementById('wi202-run');if(!run)return;run.addEventListener('click',function(){var taxpayer=document.getElementById('wi202-taxpayer').value;var normal=Math.max(0,Number(document.getElementById('wi202-normal').value||0));var special=Math.max(0,Number(document.getElementById('wi202-special').value||0));var credit=Math.max(0,Number(document.getElementById('wi202-credit').value||0));var slab=wi202SlabTax(normal);var rebate=0;if(taxpayer==='resident-individual'&&normal<=1200000){rebate=Math.min(slab,60000);}var afterRebate=Math.max(0,slab-rebate);var specialTax=special*.30;var taxBeforeCess=afterRebate+specialTax;var cess=taxBeforeCess*.04;var total=taxBeforeCess+cess;var payable=total-credit;document.getElementById('wi202-result').innerHTML='<strong>Normal slab tax:</strong> '+wi202Format(slab)+'<br><strong>Rebate modelled:</strong> '+wi202Format(rebate)+'<br><strong>Special-rate tax:</strong> '+wi202Format(specialTax)+'<br><strong>Cess:</strong> '+wi202Format(cess)+'<br><strong>Total liability:</strong> '+wi202Format(total)+'<br><strong>'+ (payable>=0?'Payable':'Refund') +':</strong> '+wi202Format(Math.abs(payable));});});
</script>`;
}

function schema(page) {
  const url = `https://workindex.co.in/seo-pages/${page.slug}.html`;
  const graph = [
    { '@type': 'Organization', '@id': 'https://workindex.co.in/#organization', name: 'WorkIndex', url: 'https://workindex.co.in' },
    { '@type': 'WebPage', '@id': `${url}#webpage`, url, name: page.title, description: page.meta },
    { '@type': 'BreadcrumbList', itemListElement: [{ '@type': 'ListItem', position: 1, name: 'WorkIndex', item: 'https://workindex.co.in' }, { '@type': 'ListItem', position: 2, name: page.h1, item: url }] },
    { '@type': 'FAQPage', mainEntity: page.faqs.map(([q, a]) => ({ '@type': 'Question', name: q, acceptedAnswer: { '@type': 'Answer', text: a.replace(/<[^>]+>/g, '') } })) }
  ];
  if (/calculator/i.test(page.type)) {
    graph.push({ '@type': 'SoftwareApplication', name: page.h1, applicationCategory: 'FinanceApplication', operatingSystem: 'Web', offers: { '@type': 'Offer', price: '0', priceCurrency: 'INR' } });
  } else {
    graph.push({ '@type': 'Service', name: page.h1, serviceType: page.type, provider: { '@id': 'https://workindex.co.in/#organization' }, areaServed: { '@type': 'Country', name: 'India' }, description: page.meta });
  }
  return JSON.stringify({ '@context': 'https://schema.org', '@graph': graph });
}

