function page(slug, type, title, meta, h1, subtitle, summary, points, useCases, records, mistakes, related, refType = 'tax', faqs) {
  if (!Array.isArray(related) && Array.isArray(mistakes)) {
    const inferredRefType = typeof related === 'string' ? related : refType;
    related = mistakes;
    mistakes = records;
    records = useCases;
    useCases = points;
    refType = inferredRefType || 'tax';
  }
  if (!Array.isArray(related)) {
    throw new Error(`${slug} has invalid related links`);
  }
  return {
    slug, type, title, meta, h1, subtitle, summary, points, useCases, records, mistakes, related, refType,
    process: ['Confirm the applicable year, taxpayer type, state, registration status and portal form before acting.', 'Reconcile the official portal data with books, bank statements, certificates, invoices and notices.', 'Prepare a written computation, filing note, document checklist or response with assumptions clearly stated.', 'Download acknowledgements, challans, workings and evidence after filing or submission.'],
    faqs: faqs || [
      ['Can WorkIndex help with this?', 'Yes. Post the facts and documents; relevant experts can quote for filing, advisory, reconciliation, registration, appeal support or ongoing compliance.'],
      ['Is the page a substitute for professional advice?', 'No. Use it to prepare. A professional should check the current portal utility, official source and records before filing or taking a tax position.'],
      ['What should I mention while posting?', 'Mention the year, state, form, deadline, amount involved, documents available, portal status and whether you need filing, correction, opinion or representation.']
    ]
  };
}

